add_action('wp_ajax_sn_submit_booking','sn_bk');add_action('wp_ajax_nopriv_sn_submit_booking','sn_bk');
function sn_bk(){
    if(!wp_verify_nonce($_POST['sn_nonce']??'','sn_booking'))wp_send_json_error(['message'=>'Session expirée.']);
    if(!empty($_POST['sn_website']))wp_send_json_success();
    $n=sanitize_text_field($_POST['sn_name']??'');$e=sanitize_email($_POST['sn_email']??'');
    $p=sanitize_text_field($_POST['sn_phone']??'');$d=sanitize_text_field($_POST['sn_date']??'');
    if(!$n||!$e||!$p||!$d)wp_send_json_error(['message'=>'Tous les champs sont obligatoires.']);
    if(!is_email($e))wp_send_json_error(['message'=>'Email invalide.']);
    $body="RESERVATION SHAMPOUINEUSE\n".str_repeat('-',30)."\nNom: $n\nEmail: $e\nTel: $p\nDate: $d\nRetrait: Reze\n".str_repeat('-',30)."\n".current_time('d/m/Y H:i');
    $h=['Content-Type: text/plain; charset=UTF-8','Reply-To: '.$n.' <'.$e.'>'];
    wp_mail('shampouineusenantes@gmail.com','Reservation - '.$n,$body,$h)?wp_send_json_success():wp_send_json_error(['message'=>"Erreur d'envoi."]);
}

